/**
 * Use this method to edit name and icon of a topic in a forum supergroup chat
 * or a private chat with a user. In the case of a supergroup chat the bot must
 * be an administrator in the chat for this to work and must have the
 * can_manage_topics administrator rights, unless it is the creator of the topic
 */
export const editForumTopic = HttpApiEndpoint.post("editForumTopic", "/editForumTopic", {
	payload: Schema.Struct({
		/**
		 * Unique identifier for the target chat or username of the target supergroup
		 * in the format @username
		 */
		chat_id: Schema.Union([Schema.Int, Schema.String]).pipe(
			Schema.annotate({
				description:
					"Unique identifier for the target chat or username of the target supergroup in the format @username",
			}),
		),
		/**
		 * Unique identifier for the target message thread of the forum topic
		 */
		message_thread_id: Schema.Int.pipe(
			Schema.annotate({ description: "Unique identifier for the target message thread of the forum topic" }),
		),
		/**
		 * New topic name, 0-128 characters. If not specified or empty, the current
		 * name of the topic will be kept.
		 */
		name: Schema.optional(Schema.String).pipe(
			Schema.annotate({
				description:
					"New topic name, 0-128 characters. If not specified or empty, the current name of the topic will be kept.",
			}),
		),
		/**
		 * New unique identifier of the custom emoji shown as the topic icon. Use
		 * getForumTopicIconStickers to get all allowed custom emoji identifiers. Pass
		 * an empty string to remove the icon. If not specified, the current icon will
		 * be kept.
		 */
		icon_custom_emoji_id: Schema.optional(Schema.String).pipe(
			Schema.annotate({
				description:
					"New unique identifier of the custom emoji shown as the topic icon. Use getForumTopicIconStickers to get all allowed custom emoji identifiers. Pass an empty string to remove the icon. If not specified, the current icon will be kept.",
			}),
		),
	}).pipe(
		Schema.annotate({
			description:
				"Use this method to edit name and icon of a topic in a forum supergroup chat or a private chat with a user. In the case of a supergroup chat the bot must be an administrator in the chat for this to work and must have the can_manage_topics administrator rights, unless it is the creator of the topic",
		}),
		Schema.toCodecJson,
		HttpApiSchema.asJson(),
	),
	success: Schema.Struct({
		ok: Schema.Literal(true),
		result: Schema.Literal(true),
	}).pipe(Schema.toCodecJson, HttpApiSchema.asJson()),
	error: [
		Errors.ChatIdEmptyError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NotEnoughRightsToEditTopicError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(404)),
		Errors.UnauthorizedError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(401)),
	],
});

