/**
 * Use this method to forward messages of any kind. Service messages and
 * messages with protected content can't be forwarded. On success, the sent
 * Message
 */
export const forwardMessage = HttpApiEndpoint.post("forwardMessage", "/forwardMessage", {
	payload: Schema.Struct({
		/**
		 * Unique identifier for the target chat or username of the target bot,
		 * supergroup or channel in the format @username
		 */
		chat_id: Schema.Union([Schema.Int, Schema.String]).pipe(
			Schema.annotate({
				description:
					"Unique identifier for the target chat or username of the target bot, supergroup or channel in the format @username",
			}),
		),
		/**
		 * Unique identifier for the target message thread (topic) of a forum; for
		 * forum supergroups and private chats of bots with forum topic mode enabled
		 * only
		 */
		message_thread_id: Schema.optional(Schema.Int).pipe(
			Schema.annotate({
				description:
					"Unique identifier for the target message thread (topic) of a forum; for forum supergroups and private chats of bots with forum topic mode enabled only",
			}),
		),
		/**
		 * Identifier of the direct messages topic to which the message will be
		 * forwarded; required if the message is forwarded to a direct messages chat
		 */
		direct_messages_topic_id: Schema.optional(Schema.Int).pipe(
			Schema.annotate({
				description:
					"Identifier of the direct messages topic to which the message will be forwarded; required if the message is forwarded to a direct messages chat",
			}),
		),
		/**
		 * Unique identifier for the chat where the original message was sent (or
		 * username of the target bot, supergroup or channel in the format @username)
		 */
		from_chat_id: Schema.Union([Schema.Int, Schema.String]).pipe(
			Schema.annotate({
				description:
					"Unique identifier for the chat where the original message was sent (or username of the target bot, supergroup or channel in the format @username)",
			}),
		),
		/**
		 * New start timestamp for the forwarded video in the message
		 */
		video_start_timestamp: Schema.optional(Schema.Int).pipe(
			Schema.annotate({ description: "New start timestamp for the forwarded video in the message" }),
		),
		/**
		 * Sends the message silently. Users will receive a notification with no
		 * sound.
		 */
		disable_notification: Schema.optional(Schema.Boolean).pipe(
			Schema.annotate({ description: "Sends the message silently. Users will receive a notification with no sound." }),
		),
		/**
		 * Protects the contents of the forwarded message from forwarding and saving
		 */
		protect_content: Schema.optional(Schema.Boolean).pipe(
			Schema.annotate({ description: "Protects the contents of the forwarded message from forwarding and saving" }),
		),
		/**
		 * Unique identifier of the message effect to be added to the message; only
		 * available when forwarding to private chats
		 */
		message_effect_id: Schema.optional(Schema.String).pipe(
			Schema.annotate({
				description:
					"Unique identifier of the message effect to be added to the message; only available when forwarding to private chats",
			}),
		),
		/**
		 * A JSON-serialized object containing the parameters of the suggested post to
		 * send; for direct messages chats only
		 */
		suggested_post_parameters: Schema.optional(Objects.SuggestedPostParameters).pipe(
			Schema.annotate({
				description:
					"A JSON-serialized object containing the parameters of the suggested post to send; for direct messages chats only",
			}),
		),
		/**
		 * Message identifier in the chat specified in from_chat_id
		 */
		message_id: Schema.Int.pipe(
			Schema.annotate({ description: "Message identifier in the chat specified in from_chat_id" }),
		),
	}).pipe(
		Schema.annotate({
			description:
				"Use this method to forward messages of any kind. Service messages and messages with protected content can't be forwarded. On success, the sent Message",
		}),
		Schema.toCodecJson,
		HttpApiSchema.asJson(),
	),
	success: Schema.Struct({
		ok: Schema.Literal(true),
		result: Objects.Message,
	}).pipe(Schema.toCodecJson, HttpApiSchema.asJson()),
	error: [
		Errors.ChatIdEmptyError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.ChatNotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.FromChatIdRequiredError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.MessageThreadNotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.MessageToForwardNotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(404)),
		Errors.UnauthorizedError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(401)),
	],
});

/**
 * Use this method to forward multiple messages of any kind. If some of the
 * specified messages can't be found or forwarded, they are skipped. Service
 * messages and messages with protected content can't be forwarded. Album
 * grouping is kept for forwarded messages. On success, an array of MessageId of
 * the sent messages
 */
export const forwardMessages = HttpApiEndpoint.post("forwardMessages", "/forwardMessages", {
	payload: Schema.Struct({
		/**
		 * Unique identifier for the target chat or username of the target bot,
		 * supergroup or channel in the format @username
		 */
		chat_id: Schema.Union([Schema.Int, Schema.String]).pipe(
			Schema.annotate({
				description:
					"Unique identifier for the target chat or username of the target bot, supergroup or channel in the format @username",
			}),
		),
		/**
		 * Unique identifier for the target message thread (topic) of a forum; for
		 * forum supergroups and private chats of bots with forum topic mode enabled
		 * only
		 */
		message_thread_id: Schema.optional(Schema.Int).pipe(
			Schema.annotate({
				description:
					"Unique identifier for the target message thread (topic) of a forum; for forum supergroups and private chats of bots with forum topic mode enabled only",
			}),
		),
		/**
		 * Identifier of the direct messages topic to which the messages will be
		 * forwarded; required if the messages are forwarded to a direct messages chat
		 */
		direct_messages_topic_id: Schema.optional(Schema.Int).pipe(
			Schema.annotate({
				description:
					"Identifier of the direct messages topic to which the messages will be forwarded; required if the messages are forwarded to a direct messages chat",
			}),
		),
		/**
		 * Unique identifier for the chat where the original messages were sent (or
		 * username of the target bot, supergroup or channel in the format @username)
		 */
		from_chat_id: Schema.Union([Schema.Int, Schema.String]).pipe(
			Schema.annotate({
				description:
					"Unique identifier for the chat where the original messages were sent (or username of the target bot, supergroup or channel in the format @username)",
			}),
		),
		/**
		 * A JSON-serialized list of 1-100 identifiers of messages in the chat
		 * from_chat_id to forward. The identifiers must be specified in a strictly
		 * increasing order.
		 */
		message_ids: Schema.Array(Schema.Int).pipe(
			Schema.annotate({
				description:
					"A JSON-serialized list of 1-100 identifiers of messages in the chat from_chat_id to forward. The identifiers must be specified in a strictly increasing order.",
			}),
		),
		/**
		 * Sends the messages silently. Users will receive a notification with no
		 * sound.
		 */
		disable_notification: Schema.optional(Schema.Boolean).pipe(
			Schema.annotate({ description: "Sends the messages silently. Users will receive a notification with no sound." }),
		),
		/**
		 * Protects the contents of the forwarded messages from forwarding and saving
		 */
		protect_content: Schema.optional(Schema.Boolean).pipe(
			Schema.annotate({ description: "Protects the contents of the forwarded messages from forwarding and saving" }),
		),
	}).pipe(
		Schema.annotate({
			description:
				"Use this method to forward multiple messages of any kind. If some of the specified messages can't be found or forwarded, they are skipped. Service messages and messages with protected content can't be forwarded. Album grouping is kept for forwarded messages. On success, an array of MessageId of the sent messages",
		}),
		Schema.toCodecJson,
		HttpApiSchema.asJson(),
	),
	success: Schema.Struct({
		ok: Schema.Literal(true),
		result: Schema.Array(Objects.MessageId),
	}).pipe(Schema.toCodecJson, HttpApiSchema.asJson()),
	error: [
		Errors.FromChatIdRequiredError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NoMessagesToForwardError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(404)),
		Errors.UnauthorizedError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(401)),
	],
});

