/**
 * Use this method to stream a partial message to a user while the message is
 * being generated. Note that the streamed draft is ephemeral and acts as a
 * temporary 30-second preview - once the output is finalized, you must call
 * sendMessage with the complete message to persist it in the user's chat
 */
export const sendMessageDraft = HttpApiEndpoint.post("sendMessageDraft", "/sendMessageDraft", {
	payload: Schema.Struct({
		/**
		 * Unique identifier for the target private chat
		 */
		chat_id: Schema.Int.pipe(Schema.annotate({ description: "Unique identifier for the target private chat" })),
		/**
		 * Unique identifier for the target message thread
		 */
		message_thread_id: Schema.optional(Schema.Int).pipe(
			Schema.annotate({ description: "Unique identifier for the target message thread" }),
		),
		/**
		 * Unique identifier of the message draft; must be non-zero. Changes of drafts
		 * with the same identifier are animated.
		 */
		draft_id: Schema.Int.pipe(
			Schema.annotate({
				description:
					"Unique identifier of the message draft; must be non-zero. Changes of drafts with the same identifier are animated.",
			}),
		),
		/**
		 * Text of the message to be sent, 0-4096 characters after entities parsing.
		 * Pass an empty text to show a “Thinking…” placeholder.
		 */
		text: Schema.optional(Schema.String).pipe(
			Schema.annotate({
				description:
					"Text of the message to be sent, 0-4096 characters after entities parsing. Pass an empty text to show a “Thinking…” placeholder.",
			}),
		),
		/**
		 * Mode for parsing entities in the message text. See formatting options for
		 * more details.
		 */
		parse_mode: Schema.optional(Schema.String).pipe(
			Schema.annotate({
				description: "Mode for parsing entities in the message text. See formatting options for more details.",
			}),
		),
		/**
		 * A JSON-serialized list of special entities that appear in message text,
		 * which can be specified instead of parse_mode
		 */
		entities: Schema.optional(Schema.Array(Objects.MessageEntity)).pipe(
			Schema.annotate({
				description:
					"A JSON-serialized list of special entities that appear in message text, which can be specified instead of parse_mode",
			}),
		),
	}).pipe(
		Schema.annotate({
			description:
				"Use this method to stream a partial message to a user while the message is being generated. Note that the streamed draft is ephemeral and acts as a temporary 30-second preview - once the output is finalized, you must call sendMessage with the complete message to persist it in the user's chat",
		}),
		Schema.toCodecJson,
		HttpApiSchema.asJson(),
	),
	success: Schema.Struct({
		ok: Schema.Literal(true),
		result: Schema.Literal(true),
	}).pipe(Schema.toCodecJson, HttpApiSchema.asJson()),
	error: [
		Errors.ChatIdEmptyError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(404)),
		Errors.RandomIdInvalidError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.UnauthorizedError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(401)),
	],
});

