/**
 * Use this method to remove a message from the list of pinned messages in a
 * chat. In private chats and channel direct messages chats, all messages can be
 * unpinned. Conversely, the bot must be an administrator with the
 * 'can_pin_messages' right or the 'can_edit_messages' right to unpin messages
 * in groups and channels respectively
 */
export const unpinChatMessage = HttpApiEndpoint.post("unpinChatMessage", "/unpinChatMessage", {
	payload: Schema.Struct({
		/**
		 * Unique identifier of the business connection on behalf of which the message
		 * will be unpinned
		 */
		business_connection_id: Schema.optional(Schema.String).pipe(
			Schema.annotate({
				description: "Unique identifier of the business connection on behalf of which the message will be unpinned",
			}),
		),
		/**
		 * Unique identifier for the target chat or username of the target channel in
		 * the format @username
		 */
		chat_id: Schema.Union([Schema.Int, Schema.String]).pipe(
			Schema.annotate({
				description: "Unique identifier for the target chat or username of the target channel in the format @username",
			}),
		),
		/**
		 * Identifier of the message to unpin. Required if business_connection_id is
		 * specified. If not specified, the most recent pinned message (by sending
		 * date) will be unpinned.
		 */
		message_id: Schema.optional(Schema.Int).pipe(
			Schema.annotate({
				description:
					"Identifier of the message to unpin. Required if business_connection_id is specified. If not specified, the most recent pinned message (by sending date) will be unpinned.",
			}),
		),
	}).pipe(
		Schema.annotate({
			description:
				"Use this method to remove a message from the list of pinned messages in a chat. In private chats and channel direct messages chats, all messages can be unpinned. Conversely, the bot must be an administrator with the 'can_pin_messages' right or the 'can_edit_messages' right to unpin messages in groups and channels respectively",
		}),
		Schema.toCodecJson,
		HttpApiSchema.asJson(),
	),
	success: Schema.Struct({
		ok: Schema.Literal(true),
		result: Schema.Literal(true),
	}).pipe(Schema.toCodecJson, HttpApiSchema.asJson()),
	error: [
		Errors.MessageToUnpinNotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(404)),
		Errors.UnauthorizedError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(401)),
	],
});

/**
 * Upgrades a given regular gift to a unique gift. Requires the
 * can_transfer_and_upgrade_gifts business bot right. Additionally requires the
 * can_transfer_stars business bot right if the upgrade is paid
 */
export const upgradeGift = HttpApiEndpoint.post("upgradeGift", "/upgradeGift", {
	payload: Schema.Struct({
		/**
		 * Unique identifier of the business connection
		 */
		business_connection_id: Schema.String.pipe(
			Schema.annotate({ description: "Unique identifier of the business connection" }),
		),
		/**
		 * Unique identifier of the regular gift that should be upgraded to a unique
		 * one
		 */
		owned_gift_id: Schema.String.pipe(
			Schema.annotate({ description: "Unique identifier of the regular gift that should be upgraded to a unique one" }),
		),
		/**
		 * Pass True to keep the original gift text, sender and receiver in the
		 * upgraded gift
		 */
		keep_original_details: Schema.optional(Schema.Boolean).pipe(
			Schema.annotate({
				description: "Pass True to keep the original gift text, sender and receiver in the upgraded gift",
			}),
		),
		/**
		 * The amount of Telegram Stars that will be paid for the upgrade from the
		 * business account balance. If gift.prepaid_upgrade_star_count > 0, then pass
		 * 0, otherwise, the can_transfer_stars business bot right is required and
		 * gift.upgrade_star_count must be passed.
		 */
		star_count: Schema.optional(Schema.Int).pipe(
			Schema.annotate({
				description:
					"The amount of Telegram Stars that will be paid for the upgrade from the business account balance. If gift.prepaid_upgrade_star_count > 0, then pass 0, otherwise, the can_transfer_stars business bot right is required and gift.upgrade_star_count must be passed.",
			}),
		),
	}).pipe(
		Schema.annotate({
			description:
				"Upgrades a given regular gift to a unique gift. Requires the can_transfer_and_upgrade_gifts business bot right. Additionally requires the can_transfer_stars business bot right if the upgrade is paid",
		}),
		Schema.toCodecJson,
		HttpApiSchema.asJson(),
	),
	success: Schema.Struct({
		ok: Schema.Literal(true),
		result: Schema.Literal(true),
	}).pipe(Schema.toCodecJson, HttpApiSchema.asJson()),
	error: [
		Errors.BusinessConnectionNotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(404)),
		Errors.UnauthorizedError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(401)),
	],
});

/**
 * Verifies a chat on behalf of the organization which is represented by the bot
 */
export const verifyChat = HttpApiEndpoint.post("verifyChat", "/verifyChat", {
	payload: Schema.Struct({
		/**
		 * Unique identifier for the target chat or username of the target bot,
		 * supergroup or channel in the format @username. Channel direct messages
		 * chats can't be verified.
		 */
		chat_id: Schema.Union([Schema.Int, Schema.String]).pipe(
			Schema.annotate({
				description:
					"Unique identifier for the target chat or username of the target bot, supergroup or channel in the format @username. Channel direct messages chats can't be verified.",
			}),
		),
		/**
		 * Custom description for the verification; 0-70 characters. Must be empty if
		 * the organization isn't allowed to provide a custom verification
		 * description.
		 */
		custom_description: Schema.optional(Schema.String).pipe(
			Schema.annotate({
				description:
					"Custom description for the verification; 0-70 characters. Must be empty if the organization isn't allowed to provide a custom verification description.",
			}),
		),
	}).pipe(
		Schema.annotate({ description: "Verifies a chat on behalf of the organization which is represented by the bot" }),
		Schema.toCodecJson,
		HttpApiSchema.asJson(),
	),
	success: Schema.Struct({
		ok: Schema.Literal(true),
		result: Schema.Literal(true),
	}).pipe(Schema.toCodecJson, HttpApiSchema.asJson()),
	error: [
		Errors.BotVerifierForbiddenError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.ChatIdEmptyError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(400)),
		Errors.NotFoundError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(404)),
		Errors.UnauthorizedError.pipe(Schema.toCodecJson, HttpApiSchema.asJson(), HttpApiSchema.status(401)),
	],
});

